module coffee_machine (
	input clk,
	input resetn,
	input brew,
	input stop,
	output reg brewing);

	parameter IDLE=0, BREWING=1;
	reg COFFEE_MACHINE_state, next_state;

	always @(posedge clk) begin
		if (~resetn) COFFEE_MACHINE_state <= IDLE;
		else COFFEE_MACHINE_state <= next_state;
	end

	always_comb begin
		case (COFFEE_MACHINE_state)
			IDLE: next_state = brew ? BREWING : IDLE;
			BREWING: next_state = stop ? IDLE : BREWING;
			default: next_state = IDLE;
		endcase
	end

	always @(COFFEE_MACHINE_state) begin
		case (COFFEE_MACHINE_state)
			BREWING: brewing = 1;
			default: brewing = 0;
		endcase
	end
endmodule
